def solve(grid: Array[Array[Long]], x: Long, y: Long, k: Long): Array[Array[Long]] = {
    val newGrid = grid.map(_.clone())
    val xInt = x.toInt
    val yInt = y.toInt
    val kInt = k.toInt

    for (i <- 0 until kInt) {
        val originalRow = xInt + i
        val flippedRow = xInt + kInt - 1 - i
        if (originalRow < flippedRow) {
            for (col <- yInt until yInt + kInt) {
                val temp = newGrid(originalRow)(col)
                newGrid(originalRow)(col) = newGrid(flippedRow)(col)
                newGrid(flippedRow)(col) = temp
            }
        }
    }
    newGrid
}
